theory.syntax:
WITH cte_name AS (
  SELECT ...
)
SELECT ... FROM cte_name;

example.query:
-- 1. Basic CTE replacing a derived table
WITH city_avg AS (
  SELECT city, AVG(marks) AS avg_marks FROM Students GROUP BY city
)
SELECT * FROM city_avg WHERE avg_marks > 70;

-- 2. Multiple CTEs chained together
WITH city_stats AS (
  SELECT city, COUNT(*) AS cnt, AVG(marks) AS avg_marks FROM Students GROUP BY city
),
big_cities AS (
  SELECT city FROM city_stats WHERE cnt > 1
)
SELECT * FROM big_cities;
